// src/components/ComplaintCard.jsx ke andar jahan card image render hoti hai:

export default function ComplaintCard({ complaint, onAccept, onAssign }) {
  // Check karein ki user ki real image string layout state me available hai ya nahi
  const hasPhoto = complaint.photoURL && complaint.photoURL.trim() !== "";

  return (
    <div style={{
      background: '#fff',
      border: '1px solid #DDE3E9',
      borderRadius: 12,
      overflow: 'hidden',
      display: 'flex',
      flexDirection: 'column',
      boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
    }}>
      
      {/* ─── CARD HEADER IMAGE AREA ─── */}
      <div style={{ 
        position: 'relative', 
        height: 140, 
        background: hasPhoto ? '#000' : '#1565C0', // Agar image na ho tabhi blue placeholder dikhe
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'center' 
      }}>
        {hasPhoto ? (
          <img 
            src={complaint.photoURL} 
            alt="Reported Waste" 
            style={{ 
              width: '100%', 
              height: '100%', 
              objectFit: 'cover' 
            }} 
          />
        ) : (
          <div style={{ color: '#fff', textAlign: 'center', fontSize: 12 }}>
            📷 <br /> No Photo Uploaded
          </div>
        )}

        {/* Urgency Badge if any */}
        {complaint.gtype?.urgency === 'URGENT' && (
          <span style={{ 
            position: 'absolute', top: 10, left: 10, 
            background: '#D32F2F', color: '#fff', fontSize: 10, 
            fontWeight: 'bold', padding: '3px 8px', borderRadius: 4 
          }}>
            CRITICAL
          </span>
        )}
      </div>

      {/* ─── CARD BODY DETAILS ─── */}
      <div style={{ padding: 12, flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', color: '#7A8FA6', fontSize: 10, fontWeight: 'bold' }}>
            <span>TKT-{complaint.id?.substring(0, 5) || '1000'}</span>
            <span style={{ 
              color: complaint.status === 'NEW' ? '#E65100' : '#1565C0',
              background: complaint.status === 'NEW' ? '#FFE0B2' : '#E3F2FD',
              padding: '1px 5px', borderRadius: 4
            }}>
              {complaint.status}
            </span>
          </div>
          
          <h4 style={{ margin: '6px 0 2px 0', fontSize: 14, color: '#1E293B', fontWeight: 700 }}>
            {complaint.area || 'Platform Area'} — {complaint.gtype?.label || 'Waste'}
          </h4>
          
          <div style={{ fontSize: 11, color: '#64748B', display: 'flex', alignItems: 'center', gap: 4 }}>
            📍 {complaint.station || 'Nagpur Junction'}
          </div>
        </div>

        {/* Action Button */}
        <div style={{ marginTop: 12 }}>
          {complaint.status === 'NEW' ? (
            <button 
              onClick={() => onAccept(complaint.id)}
              style={{ width: '100%', padding: '8px', background: '#1565C0', color: '#fff', border: 'none', borderRadius: 6, fontWeight: 600, cursor: 'pointer' }}
            >
              Accept Alert
            </button>
          ) : complaint.status === 'ACCEPTED' ? (
            <button 
              onClick={() => onAssign(complaint)}
              style={{ width: '100%', padding: '8px', background: '#4A148C', color: '#fff', border: 'none', borderRadius: 6, fontWeight: 600, cursor: 'pointer' }}
            >
              Assign Cleaner
            </button>
          ) : (
            <div style={{ textAlign: 'center', fontSize: 12, color: '#2E7D32', fontWeight: 600, padding: '6px', background: '#E8F5E9', borderRadius: 6 }}>
              👷‍♂️ {complaint.assignedTo || 'In Progress'}
            </div>
          )}
        </div>
      </div>

    </div>
  );
}
